SELECT t.latitude, t.longitude, a.agency_name
FROM tickets t
JOIN agencies a ON t.agency_name = a.agency_name;

SELECT COUNT(DISTINCT violation_code)
FROM tickets
WHERE inspector_name = 'Sims, Martinzie';

SELECT SUM(fine_amount) AS total_fine_amount, SUM(admin_fee) AS total_admin_fee
FROM tickets
WHERE ticket_id = (SELECT LAST_INSERT_ROWID());

SELECT *
FROM tickets
ORDER BY violation_date ASC;

SELECT t.inspector_name, t.violation_description
FROM tickets t
WHERE t.violation_description LIKE '%Your specific word%';

SELECT t.ticket_id, v.violation_code, v.violation_description
FROM tickets t
JOIN violations v ON t.violation_code = v.violation_code;
